// Time:  O(logn)
// Space: O(1)

class Solution {
public:
    int findSpecialInteger(vector<int>& arr) {
        for (const auto& x : {arr[arr.size() / 4], arr[arr.size() / 2], arr[arr.size() * 3 / 4]}) {
            if (distance(lower_bound(arr.cbegin(), arr.cend(), x),
                         upper_bound(arr.cbegin(), arr.cend(), x)) * 4 > arr.size()) {
                return x;
            }
        }
        return -1;
    }
};

# Time:  O(logn)
# Space: O(1)

import bisect


class Solution(object):
    def findSpecialInteger(self, arr):
        """
        :type arr: List[int]
        :rtype: int
        """
        for x in [arr[len(arr)//4], arr[len(arr)//2], arr[len(arr)*3//4]]:
            if (bisect.bisect_right(arr, x) - bisect.bisect_left(arr, x)) * 4 > len(arr):
                return x
        return -1
